template:
fn sign(msg: &str, key: u8) -> Vec<u8> {
    msg.bytes().map(|b| b ^ key).collect()
}

fn verify(msg: &str, sig: &[u8], key: u8) -> bool {
    let decoded: Vec<u8> = sig.iter().map(|b| b ^ key).collect();
    decoded == msg.as_bytes()
}

